import numpy as np

class MixingAnalyzer:
    def __init__(self, boltzmann_machine):
        self.bm = boltzmann_machine

    def compute_autocorrelation(self, samples, max_lag=100):
        n = len(samples)
        if samples.ndim > 1:
            # Use first component or sum
            samples = np.sum(samples, axis=1)

        mean = np.mean(samples)
        var = np.var(samples)

        if var < 1e-10:
            return np.zeros(max_lag)

        centered = samples - mean

        autocorr = []
        for lag in range(max_lag):
            if lag == 0:
                autocorr.append(1.0)
            else:
                c = np.mean(centered[:-lag] * centered[lag:])
                autocorr.append(c / var)

        return np.array(autocorr)

    def estimate_integrated_autocorr_time(self, samples):
        autocorr = self.compute_autocorrelation(samples)

        # Sum until autocorrelation becomes negative or negligible
        tau_int = 0.5  # Start with 0.5 for lag 0

        for lag in range(1, len(autocorr)):
            if autocorr[lag] < 0.05:
                break
            tau_int += autocorr[lag]

        return tau_int

    def compute_effective_sample_size(self, samples):
        tau_int = self.estimate_integrated_autocorr_time(samples)
        n = len(samples)
        ess = n / (2 * tau_int)
        return ess

    def _run_chain(self, n_samples, v_init=None):
        if v_init is None:
            v = np.random.randint(0, 2, self.bm.n_visible).astype(float)
        else:
            v = v_init.copy()

        samples = []
        for _ in range(n_samples):
            h = self.bm.sample_h_given_v(v)
            v = self.bm.sample_v_given_h(h)
            samples.append(v.copy())

        return np.array(samples)

    def diagnose_convergence(self, n_chains=4, n_samples=1000):
        # Run multiple chains from different starting points
        chains = []
        for i in range(n_chains):
            np.random.seed(i * 100)
            v_init = np.random.randint(0, 2, self.bm.n_visible).astype(float)
            chain = self._run_chain(n_samples, v_init)
            chains.append(chain)

        chains = np.array(chains)  # (n_chains, n_samples, n_visible)

        # Gelman-Rubin diagnostic (simplified)
        # Use second half of chains
        chains = chains[:, n_samples//2:, :]
        n = chains.shape[1]

        # Within-chain variance
        W = np.mean(np.var(chains, axis=1), axis=0)

        # Between-chain variance
        chain_means = np.mean(chains, axis=1)
        B = n * np.var(chain_means, axis=0)

        # Estimated variance
        var_est = ((n - 1) / n) * W + (1 / n) * B

        # R-hat (potential scale reduction factor)
        R_hat = np.sqrt(var_est / (W + 1e-10))

        # Effective sample size per chain
        ess_per_chain = [self.compute_effective_sample_size(chain.sum(axis=1)) 
                         for chain in chains]

        return {
            'R_hat': R_hat,
            'R_hat_mean': np.mean(R_hat),
            'converged': np.all(R_hat < 1.1),
            'ess_per_chain': ess_per_chain,
            'total_ess': sum(ess_per_chain)
        }
